mapper.select:
select * from review where postId = #{postId}


        order by ${sortField} ${sortOrder}


        order by reviewTime desc, reviewId desc


limit #{offset}, #{size}

select * from review where orderId = #{orderId}


        order by ${sortField} ${sortOrder}


        order by reviewTime desc, reviewId desc


limit #{offset}, #{size}

select r.*
from review r
inner join `order` o on r.orderId = o.orderId
inner join transaction t on o.transactionId = t.transactionId
